<?php
if(!defined('ABSPATH')){exit;}
class LEF_DB_Handler{
public static function init(){add_action('wp_ajax_lef_db_refresh',[__CLASS__,'ajax_refresh']);add_action('wp_ajax_lef_db_repair',[__CLASS__,'ajax_repair']);}
public static function get_table_status($table_name){global $wpdb;$status=['created'=>false,'complete'=>false];$exists=$wpdb->get_var($wpdb->prepare("SHOW TABLES LIKE %s",$table_name))===$table_name;if(!$exists){return $status;}$status['created']=true;if(!function_exists('lef_get_db_schemas')){require_once LEF_PLUGIN_DIR.'includes/db-schema.php';}$schemas=lef_get_db_schemas();if(!isset($schemas[$table_name])){return $status;}$schema=$schemas[$table_name];preg_match_all('/^\s*([a-zA-Z0-9_]+)\s+[a-zA-Z]+/m',$schema,$matches);$expected_columns=[];if(!empty($matches[1])){foreach($matches[1] as $col){$col_lower=strtolower($col);$ignore_keywords=['primary','key','unique','create','table','constraint','foreign','index','default'];if(!in_array($col_lower,$ignore_keywords)){$expected_columns[]=$col_lower;}}}$existing_columns_raw=$wpdb->get_results("SHOW COLUMNS FROM {$table_name}");$existing_columns=[];if($existing_columns_raw){foreach($existing_columns_raw as $col_data){$existing_columns[]=strtolower($col_data->Field);}}$missing=array_diff($expected_columns,$existing_columns);if(empty($missing)){$status['complete']=true;}return $status;}
public static function ajax_refresh(){$table_name=isset($_POST['table'])?sanitize_text_field(wp_unslash($_POST['table'])):'';if(!$table_name){wp_send_json_error(['message'=>'Table name is required.']);}$status=self::get_table_status($table_name);wp_send_json_success($status);}
public static function ajax_repair(){$table_name=isset($_POST['table'])?sanitize_text_field(wp_unslash($_POST['table'])):'';if(!$table_name){wp_send_json_error(['message'=>'Table name is required.']);}if(!function_exists('lef_get_db_schemas')){require_once LEF_PLUGIN_DIR.'includes/db-schema.php';}$schemas=lef_get_db_schemas();if(!isset($schemas[$table_name])){wp_send_json_error(['message'=>'Table schema not found.']);}require_once(ABSPATH.'wp-admin/includes/upgrade.php');dbDelta($schemas[$table_name]);$status=self::get_table_status($table_name);wp_send_json_success($status);}
}
LEF_DB_Handler::init();